40	// ExecutionCleanupLiveness records the refreshable liveness signal attached to
41	// a temp execution directory.
42	type ExecutionCleanupLiveness struct {
43		PID          int       `json:"pid,omitempty"`
44		SessionID    string    `json:"session_id,omitempty"`
45		RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
46		ExpiresAt    time.Time `json:"expires_at,omitempty"`
47		LastChecked  time.Time `json:"last_checked,omitempty"`
48		HeartbeatSeq int       `json:"heartbeat_seq,omitempty"`
49	}
