51	// ExecutionCleanupMetadata records the ownership metadata for one DDx temp
52	// execution directory.
53	type ExecutionCleanupMetadata struct {
54		ProjectRoot  string `json:"project_root,omitempty"`
55		BeadID       string `json:"bead_id,omitempty"`
56		AttemptID    string `json:"attempt_id,omitempty"`
57		WorktreePath string `json:"worktree_path,omitempty"`
58		Registered   bool   `json:"registered,omitempty"`
59		Preserved    bool   `json:"preserved,omitempty"`
60		// ActiveCandidateCycle is set by AttemptCycleCoordinator while it holds the
61		// worktree open for candidate evaluation (checks, review, repair). The
62		// cleanup manager preserves any worktree with this flag set so it is never
63		// deleted mid-cycle before the coordinator reaches terminal disposition.
64		ActiveCandidateCycle bool `json:"active_candidate_cycle,omitempty"`
65		// Candidate-cycle metadata lets crash recovery distinguish a stale
66		// unpinned worktree from one that still has a project-root candidate ref
67		// worth preserving for operator inspection.
68		CandidateCyclePhase string                    `json:"candidate_cycle_phase,omitempty"`
69		CandidateRef        string                    `json:"candidate_ref,omitempty"`
70		CandidateRev        string                    `json:"candidate_rev,omitempty"`
71		CycleIndex          int                       `json:"cycle_index,omitempty"`
72		ReviewActive        bool                      `json:"review_active,omitempty"`
73		RepairActive        bool                      `json:"repair_active,omitempty"`
74		CreatedAt           time.Time                 `json:"created_at,omitempty"`
75		Liveness            *ExecutionCleanupLiveness `json:"liveness,omitempty"`
76	}
