843	func (m *ExecutionCleanupManager) removeStaleRunState(state RunState, summary *ExecutionCleanupSummary) (bool, int64) {
844		path := runStatePath(m.ProjectRoot)
845		clear := func() error {
846			return ClearRunState(m.ProjectRoot)
847		}
848		if state.AttemptID != "" {
849			if attemptPath, err := runStateAttemptPath(m.ProjectRoot, state.AttemptID); err == nil {
850				path = attemptPath
851				clear = func() error {
852					return ClearRunStateAttempt(m.ProjectRoot, state.AttemptID)
853				}
854			}
855		}
856	
857		var bytes int64
858		present := false
859		if info, statErr := os.Stat(path); statErr == nil {
860			present = true
861			bytes = info.Size()
862		} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
863			path = runStatePath(m.ProjectRoot)
864			if info, legacyErr := os.Stat(path); legacyErr == nil {
865				present = true
866				bytes = info.Size()
867				clear = func() error {
868					return ClearRunState(m.ProjectRoot)
869				}
870			}
871		}
872		if !m.DryRun {
873			if err := clear(); err != nil {
874				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
875					Path:    path,
876					Class:   "run_state_clear",
877					Message: err.Error(),
878				})
879			}
880		}
881		if !present {
882			return false, 0
883		}
884		class := "removed_run_state"
885		if m.DryRun {
886			class = "would_remove_run_state"
887		}
888		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
889			Path:    path,
890			Class:   class,
891			Message: "stale run-state",
892			Bytes:   bytes,
893			Inodes:  1,
894		})
895		return true, bytes
896	}
