1024	func measureTree(path string) (bytes int64, inodes int64, err error) {
1025		info, err := os.Lstat(path)
1026		if err != nil {
1027			return 0, 0, err
1028		}
1029		if !info.IsDir() {
1030			return info.Size(), 1, nil
1031		}
1032		err = filepath.WalkDir(path, func(p string, d os.DirEntry, walkErr error) error {
1033			if walkErr != nil {
1034				return walkErr
1035			}
1036			inodes++
1037			fi, statErr := d.Info()
1038			if statErr != nil {
1039				return statErr
1040			}
1041			bytes += fi.Size()
1042			return nil
1043		})
1044		return bytes, inodes, err
1045	}
