1047	// pruneEvidenceDirs deletes .ddx/executions/<attempt-id>/ dirs whose mtime
1048	// is older than m.RetainDays. Dirs referenced by active run-states or lacking
1049	// a result.json are preserved. No-op when RetainDays == 0 (disabled).
1050	func (m *ExecutionCleanupManager) pruneEvidenceDirs(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
1051		if m.RetainDays == 0 {
1052			return
1053		}
1054		cutoff := now.AddDate(0, 0, -m.RetainDays)
1055	
1056		activeAttempts := map[string]struct{}{}
1057		for _, rs := range runStates {
1058			if rs.AttemptID != "" {
1059				activeAttempts[rs.AttemptID] = struct{}{}
1060			}
1061		}
1062	
1063		root := filepath.Join(m.ProjectRoot, filepath.FromSlash(ExecuteBeadArtifactDir))
1064		entries, err := os.ReadDir(root)
1065		if err != nil {
1066			if !errors.Is(err, os.ErrNotExist) {
1067				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1068					Path:    root,
1069					Class:   "evidence_dir_read",
1070					Message: err.Error(),
1071				})
1072			}
1073			return
1074		}
1075	
1076		for _, entry := range entries {
1077			if !entry.IsDir() {
1078				continue
1079			}
1080			dirName := entry.Name()
1081			dirPath := filepath.Join(root, dirName)
1082			relPath := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, dirName))
1083	
1084			if _, ok := activeAttempts[dirName]; ok {
1085				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1086					Path:    relPath,
1087					Class:   "preserved_active_evidence_dir",
1088					Message: "active run-state reference",
1089				})
1090				continue
1091			}
1092	
1093			// Defensive: skip dirs with no result.json (may be in-flight).
1094			if _, statErr := os.Stat(filepath.Join(dirPath, "result.json")); statErr != nil {
1095				continue
1096			}
1097	
1098			info, infoErr := entry.Info()
1099			if infoErr != nil {
1100				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1101					Path:    dirPath,
1102					Class:   "evidence_dir_stat",
1103					Message: infoErr.Error(),
1104				})
1105				continue
1106			}
1107			if !info.ModTime().Before(cutoff) {
1108				continue
1109			}
1110	
1111			if !m.DryRun {
1112				m.removeEvidenceDir(ctx, dirPath, summary)
1113			}
1114			summary.RemovedEvidenceDirs++
1115			class := "removed_evidence_dir"
1116			if m.DryRun {
1117				class = "would_remove_evidence_dir"
1118			}
1119			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1120				Path:    relPath,
1121				Class:   class,
1122				Message: fmt.Sprintf("evidence dir older than %d days", m.RetainDays),
1123			})
1124		}
1125	}
