1127	// removeEvidenceDir stages tracked files for deletion via git rm, then
1128	// removes any remaining files with os.RemoveAll.
1129	func (m *ExecutionCleanupManager) removeEvidenceDir(ctx context.Context, dirPath string, summary *ExecutionCleanupSummary) {
1130		if m.ProjectRoot == "" {
1131			_ = os.RemoveAll(dirPath)
1132			return
1133		}
1134		rel, err := filepath.Rel(m.ProjectRoot, dirPath)
1135		if err != nil || strings.HasPrefix(rel, "..") {
1136			_ = os.RemoveAll(dirPath)
1137			return
1138		}
1139		relSlash := filepath.ToSlash(rel)
1140	
1141		// Check for tracked files; if any, stage their deletion via git rm.
1142		lsOut, lsErr := internalgit.Command(ctx, m.ProjectRoot, "ls-files", relSlash).Output()
1143		if lsErr == nil && len(strings.TrimSpace(string(lsOut))) > 0 {
1144			rmOut, rmErr := internalgit.Command(ctx, m.ProjectRoot, "rm", "-rf", relSlash).CombinedOutput()
1145			if rmErr != nil {
1146				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1147					Path:    dirPath,
1148					Class:   "evidence_dir_git_rm",
1149					Message: fmt.Sprintf("git rm: %s: %v", strings.TrimSpace(string(rmOut)), rmErr),
1150				})
1151			}
1152		}
1153		// Remove remaining untracked files.
1154		_ = os.RemoveAll(dirPath)
1155	}
