1157	func scanCompleteEvidenceDirs(projectRoot, rootRel string, primaryFile, secondaryFile string, summary *ExecutionCleanupSummary) int {
1158		root := filepath.Join(projectRoot, filepath.FromSlash(rootRel))
1159		entries, err := os.ReadDir(root)
1160		if err != nil {
1161			return 0
1162		}
1163		count := 0
1164		for _, entry := range entries {
