1183				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1184					Path:    filepath.ToSlash(filepath.Join(rootRel, entry.Name())),
1185					Class:   "complete_evidence",
1186					Message: "complete evidence preserved",
1187				})
1188			}
1189		}
1190		return count
1191	}
