281	// tick performs one probe cycle and returns true on a successful reach
282	// (server replied to register or to a register that was already in place).
283	func (p *Probe) tick(ctx context.Context) bool {
284		addr := ""
285		if p.cfg.AddrFunc != nil {
286			addr = p.cfg.AddrFunc()
287		}
288		if addr == "" {
289			// No server configured. Drive Connected→NotConnected if we used to
290			// be connected; otherwise no-op.
291			p.markDisconnected("no_addr")
292			return false
293		}
294	
295		// Already connected: cheap reachability check by hitting register again
296		// is overkill; we just trust the connection and let event POSTs surface
297		// failures via the failure-counter (markDisconnected is called from
298		// postEvent when the POST fails). This keeps probe traffic minimal.
299		if p.Connected() {
300			return true
301		}
302	
303		// NotConnected: attempt to register.
304		workerID, err := p.postRegister(ctx, addr)
305		if err != nil {
306			fmt.Fprintf(p.cfg.Logger, "workerprobe: register failed: %v\n", err)
307			return false
308		}
309		p.markConnected(workerID)
310	
311		// Drain the ring buffer via backfill (best-effort).
312		p.flushBackfill(ctx, addr, workerID)
313		return true
314	}
315	
316	func (p *Probe) markConnected(workerID string) {
317		p.mu.Lock()
318		p.state = stateConnected
319		p.workerID = workerID
320		p.mu.Unlock()
321	}
322	
323	func (p *Probe) markDisconnected(reason string) {
324		p.mu.Lock()
325		if p.state == stateConnected {
326			fmt.Fprintf(p.cfg.Logger, "workerprobe: disconnect (%s)\n", reason)
327		}
328		p.state = stateNotConnected
329		p.workerID = ""
330		p.mu.Unlock()
331	}
332	
333	func (p *Probe) flushBackfill(ctx context.Context, addr, workerID string) {
334		p.mu.Lock()
335		if len(p.buf) == 0 && !p.dropped {
336			p.mu.Unlock()
337			return
338		}
339		events := make([]Event, len(p.buf))
340		copy(events, p.buf)
341		dropped := p.dropped
342		p.mu.Unlock()
343	
344		if err := p.postBackfill(ctx, addr, workerID, events, dropped); err != nil {
345			fmt.Fprintf(p.cfg.Logger, "workerprobe: backfill failed: %v\n", err)
346			return
347		}
348	
349		// Success: clear the ring buffer.
350		p.mu.Lock()
351		p.buf = p.buf[:0]
352		p.dropped = false
353		p.mu.Unlock()
354	}
