431	// postBackfill replays the NotConnected ring buffer.
432	func (p *Probe) postBackfill(ctx context.Context, addr, workerID string, events []Event, dropped bool) error {
433		body, err := json.Marshal(struct {
434			Events  []Event `json:"events"`
435			Dropped bool    `json:"dropped,omitempty"`
436		}{Events: events, Dropped: dropped})
437		if err != nil {
438			return err
439		}
440		req, err := http.NewRequestWithContext(ctx, http.MethodPost, addr+"/api/workers/"+workerID+"/backfill", bytes.NewReader(body))
441		if err != nil {
442			return err
443		}
444		req.Header.Set("Content-Type", "application/json")
445		resp, err := p.cfg.HTTPClient.Do(req)
446		if err != nil {
447			return err
448		}
449		defer func() { _ = resp.Body.Close() }()
450		if resp.StatusCode != http.StatusNoContent {
451			return fmt.Errorf("backfill: status=%d", resp.StatusCode)
452		}
453		return nil
454	}
