456	// TeeJSONL returns an io.Writer that forwards every write to base AND parses
457	// each newline-terminated JSON envelope into a workerprobe.Event fed to the
458	// probe. Envelope shape matches writeLoopEvent (session_id/type/ts/data with
459	// data.bead_id and data.attempt_id when present). Malformed lines are passed
460	// through unchanged but skipped for mirroring.
461	func TeeJSONL(base io.Writer, p *Probe) io.Writer {
462		return &teeWriter{base: base, probe: p}
463	}
464	
465	type teeWriter struct {
466		base  io.Writer
467		probe *Probe
468		buf   []byte
469	}
470	
471	func (t *teeWriter) Write(b []byte) (int, error) {
472		n, err := t.base.Write(b)
473		// Accumulate; emit one Event per newline-terminated chunk.
474		t.buf = append(t.buf, b...)
475		for {
476			i := indexByte(t.buf, '\n')
477			if i < 0 {
478				break
479			}
480			line := t.buf[:i]
481			t.buf = t.buf[i+1:]
482			t.dispatch(line)
483		}
484		return n, err
485	}
486	
487	func (t *teeWriter) dispatch(line []byte) {
488		if len(line) == 0 {
489			return
490		}
491		var env struct {
492			Type string `json:"type"`
493			Data struct {
494				BeadID    string `json:"bead_id"`
495				AttemptID string `json:"attempt_id"`
496			} `json:"data"`
497		}
498		if err := json.Unmarshal(line, &env); err != nil || env.Type == "" {
499			return
500		}
501		// Body carries the full envelope so the server log preserves structured
502		// detail (loop.start config, bead.result outcome, etc.).
503		body := json.RawMessage(append([]byte(nil), line...))
504		t.probe.RecordEvent(Event{
505			BeadID:    env.Data.BeadID,
506			AttemptID: env.Data.AttemptID,
507			Kind:      env.Type,
508			Body:      body,
509		})
510	}
511	
512	func indexByte(b []byte, c byte) int {
513		for i := range b {
514			if b[i] == c {
515				return i
516			}
517		}
518		return -1
519	}
520	
521	// applyJitter returns base scaled by a uniform random factor in
522	// [1-pct, 1+pct]. pct is clamped to [0, 1).
523	func applyJitter(base time.Duration, pct float64, r *rand.Rand) time.Duration {
524		if pct <= 0 {
525			return base
526		}
527		if pct >= 1 {
528			pct = 0.99
529		}
530		// Uniform in [-pct, +pct].
531		delta := (r.Float64()*2 - 1) * pct
532		scaled := time.Duration(float64(base) * (1 + delta))
533		if scaled < time.Millisecond {
534			scaled = time.Millisecond
535		}
536		return scaled
537	}
