// pruneAgentLogs deletes agent-*.jsonl and svc-*.jsonl files under
// .ddx/agent-logs/ whose mtime is older than m.RetainDays days. Files whose
// session_id matches an active run-state are skipped. No-op when RetainDays == 0.
func (m *ExecutionCleanupManager) pruneAgentLogs(summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
	if m.RetainDays == 0 {
		return
	}
	cutoff := now.AddDate(0, 0, -m.RetainDays)

	activeSessionIDs := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.SessionID != "" {
			activeSessionIDs[rs.SessionID] = struct{}{}
		}
	}

	root := filepath.Join(m.ProjectRoot, DefaultLogDir)
	entries, err := os.ReadDir(root)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    root,
				Class:   "agent_logs_dir_read",
				Message: err.Error(),
			})
		}
		return
	}

	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		name := entry.Name()
		if !strings.HasSuffix(name, ".jsonl") {
			continue
		}
		if !strings.HasPrefix(name, "agent-") && !strings.HasPrefix(name, "svc-") {
			continue
		}

		filePath := filepath.Join(root, name)
		relPath := filepath.ToSlash(filepath.Join(DefaultLogDir, name))

		base := strings.TrimSuffix(name, ".jsonl")
		var sessionID string
		if strings.HasPrefix(base, "agent-") {
			sessionID = strings.TrimPrefix(base, "agent-")
		} else if strings.HasPrefix(base, "svc-") {
			sessionID = strings.TrimPrefix(base, "svc-")
		}
		if sessionID != "" {
			if _, ok := activeSessionIDs[sessionID]; ok {
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    relPath,
					Class:   "preserved_active_agent_log",
					Message: "active run-state reference",
				})
				continue
			}
		}

		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    filePath,
				Class:   "agent_log_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		if !m.DryRun {
			if removeErr := os.Remove(filePath); removeErr != nil {
				summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
					Path:     filePath,
					Class:    "agent_log_remove",
					Message:  removeErr.Error(),
					Blocking: false,
				})
				continue
			}
		}
		summary.RemovedAgentLogs++
		class := "removed_agent_log"
		if m.DryRun {
			class = "would_remove_agent_log"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    relPath,
			Class:   class,
			Message: fmt.Sprintf("agent log older than %d days", m.RetainDays),
		})
	}
}

// pruneWorkerDirs deletes .ddx/workers/<id>/ directories whose mtime is older
// than m.RetainDays days. Directories with a live worker PID in status.json
// are skipped. No-op when RetainDays == 0.
func (m *ExecutionCleanupManager) pruneWorkerDirs(summary *ExecutionCleanupSummary, now time.Time) {
	if m.RetainDays == 0 {
		return
	}
	cutoff := now.AddDate(0, 0, -m.RetainDays)

	root := filepath.Join(m.ProjectRoot, ".ddx", "workers")
	entries, err := os.ReadDir(root)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    root,
				Class:   "workers_dir_read",
				Message: err.Error(),
			})
		}
		return
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		workerID := entry.Name()
		dirPath := filepath.Join(root, workerID)
		relPath := filepath.ToSlash(filepath.Join(".ddx/workers", workerID))

		statusData, statusErr := os.ReadFile(filepath.Join(dirPath, "status.json"))
		if statusErr == nil {
			var status struct {
				PID int `json:"pid"`
			}
			if jsonErr := json.Unmarshal(statusData, &status); jsonErr == nil {
				if status.PID > 0 && trackerProcessAlive(status.PID) {
					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
						Path:    relPath,
						Class:   "preserved_active_worker_dir",
						Message: "worker pid still alive",
					})
					continue
				}
			}
		}

		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "worker_dir_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		if !m.DryRun {
			if removeErr := os.RemoveAll(dirPath); removeErr != nil {
				summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
					Path:     dirPath,
					Class:    "worker_dir_remove",
					Message:  removeErr.Error(),
					Blocking: false,
				})
				continue
			}
		}
		summary.RemovedWorkerDirs++
		class := "removed_worker_dir"
		if m.DryRun {
			class = "would_remove_worker_dir"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    relPath,
			Class:   class,
			Message: fmt.Sprintf("worker dir older than %d days", m.RetainDays),
		})
	}
}

